import React, { useState, useEffect, useCallback } from 'react';
import { FlatList, ActivityIndicator, Text, View, RefreshControl } from 'react-native';

function PostList() {
  const [posts, setPosts] = useState([]);
  const [page, setPage] = useState(1);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [hasMore, setHasMore] = useState(true);

  const fetchPosts = async (pageNum, isRefresh = false) => {
    const url = `https://jsonplaceholder.typicode.com/posts?_page=${pageNum}&_limit=20`;
    setIsLoading(true);
    try {
      const response = await fetch(url);
      const data = await response.json();
      if (data.length < 20) setHasMore(false);
      if (isRefresh) {
        setPosts(data);
      } else {
        setPosts(prev => [...prev, ...data]);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
      setIsLoadingMore(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchPosts(1);
  }, []);

  const loadMore = () => {
    if (!isLoadingMore && hasMore && !isLoading) {
      setIsLoadingMore(true);
      const nextPage = page + 1;
      setPage(nextPage);
      fetchPosts(nextPage);
    }
  };

  const onRefresh = () => {
    setRefreshing(true);
    setPage(1);
    setHasMore(true);
    fetchPosts(1, true);
  };

  const renderFooter = () => {
    if (!isLoadingMore) return null;
    return &lt;ActivityIndicator style={{ margin: 20 }} /&gt;;
  };

  const renderEmpty = () => (
    &lt;View style={{ flex: 1, alignItems: 'center', marginTop: 50 }}&gt;
      &lt;Text&gt;Aucune publication&lt;/Text&gt;
    &lt;/View&gt;
  );

  return (
    &lt;FlatList
      data={posts}
      keyExtractor={(item) => item.id.toString()}
      renderItem={({ item }) => &lt;Text&gt;{item.title}&lt;/Text&gt;}
      onEndReached={loadMore}
      onEndReachedThreshold={0.5}
      ListFooterComponent={renderFooter}
      ListEmptyComponent={renderEmpty}
      refreshControl={
        &lt;RefreshControl refreshing={refreshing} onRefresh={onRefresh} /&gt;
      }
    /&gt;
  );
}

export default PostList;
```
